// // This module decrements the count on each clock cycle and sets it to 15 on reset
module sync_counter(
    input clk,
    input reset,

    output reg [3:0] count
);

always @(posedge clk or posedge reset) begin
    if (reset) begin
        count <= 4'b0000;
    end else begin
        count <= count + 1;
    end
end

endmodule
